import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        response.setContentType("text/html");

        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Code Generation</title></head>");
        out.println("<body>");

        // Properly encode user input to prevent XSS
        try {
            String encodedInput = ESAPI.encoder().encodeForHTML(userInput);
            out.println("<p>User Input: " + encodedInput + "</p>");
        } catch (EncodingException e) {
            // Handle encoding exception
            e.printStackTrace();
            out.println("<p>Error processing user input</p>");
        }

        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
